,'casino_revenue_history','SUCCESS 341731511','success','model',231.2416594028473,'2026-04-09T21:36:56.599976Z','2026-04-09T21:40:47.616103Z','2026-04-09T21:36:56.483317Z','2026-04-09T21:36:56.598566Z',341731511,False,'with casino_activity as ( --noqa: disable=all\n    select\n        cast(acco_id as integer) as acco_id, \n        settled_date_alk as dt,\n        sum(cash_bet_count) as cash_bet_count,\n        sum(total_bet_count) as total_bet_count,\n        sum(total_stake) as total_stake,\n        sum(cash_bet_stake) as cash_bet_stake,\n        sum(total_payout) as total_payout,\n        sum(total_jackpot_contribution) as total_jackpot_contribution,\n        sum(ggr) as cash_ggr,    \n        sum(ngr) as trading_ngr,\n        sum(expected_ggr) as eggr\n    from FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_DAILY_SETTLED_AGG\n    where is_test_account = 0\n    group by all\n),\n\ncommercial_bonus_costs as (\n    select\n        acco_id,\n        day as dt,\n        sum(nvl(case when transaction in (\'bonus winnings\', \'fancash jackpot contribution\') then amount end,0)) as bonus_costs,\n        sum(nvl(case when transaction in (\'bonus expected winnings\', \'fancash jackpot contribution\') then amount end,0)) as bonus_expected_costs\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.CASINO_PROMOTIONS_LEDGER\n    where transaction in (\'bonus winnings\',\'bonus expected winnings\', \'fancash jackpot contribution\')\n    group by all\n),\n\ndeposits as (\n    select\n        acco_id,\n        date(convert_timezone(\'UTC\', \'America/Anchorage\', created)) as deposit_date,\n        count(distinct created) as deposit_count,\n        sum(nvl(amount,0)) as deposit_amount \n    from FBG_SOURCE.OSB_SOURCE.DEPOSITS d\n    where status = \'DEPOSIT_SUCCESS\'\n        and deleted = 0\n    group by 1,2\n),\n\nwithdrawals as (\n    select \n        account_id as acco_id,\n        date(convert_timezone(\'UTC\', \'America/Anchorage\', initiated_at)) as withdrawal_date,\n        count(distinct initiated_at) as withdrawal_count,\n        sum(nvl(amount,0)) as withdrawal_amount\n    from FBG_SOURCE.OSB_SOURCE.WITHDRAWALS\n    where status = \'WITHDRAWAL_COMPLETED\'\n        and deleted = 0\n    group by 1,2\n),\n\ncasino_customers as (\n    select\n        acco_id,\n        min(dt) as dt \n    from (\n        select \n            acco_id, \n            min(dt) as dt \n        from casino_activity \n        group by all\n\n        union\n\n        select \n            acco_id, \n            min(dt) as dt \n        from commercial_bonus_costs \n        group by all\n\n        union\n\n        select \n            acco_id, \n            date(casino_ftu_date_alk) as dt \n        from FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART \n        where casino_ftu_date_alk is not null\n        and is_test_account = 0\n    )\n    group by all\n),\n\nrevenue_join as (\n    select\n        a.acco_id,\n        b.dt as settled_date_alk,\n        nvl(c.cash_bet_count,0) as cash_bet_count,\n        nvl(c.total_bet_count,0) as total_bet_count,\n        cast(nvl(c.cash_bet_stake,0) as decimal(15,2)) as cash_stakes,\n        cast(nvl(c.total_stake,0) as decimal(15,2)) as total_stakes,\n        cast(nvl(c.total_payout,0) as decimal(15,2)) as total_payout,\n        cast(nvl(c.total_jackpot_contribution,0) as decimal(15,2)) as total_jackpot_contribution,\n        cast(nvl(d.bonus_costs,0) as decimal(15,2)) as bonus_winnings,\n        cast(nvl(c.cash_ggr,0) as decimal(15,2)) as cash_ggr,\n        cast(nvl(c.eggr,0) as decimal(15,2)) as cash_eggr,\n        cast(nvl(c.total_stake,0) - nvl(c.total_payout,0) - nvl(c.total_jackpot_contribution,0) as decimal(15,2)) as total_ggr,\n        cast(nvl(c.cash_ggr,0) - nvl(d.bonus_costs,0) as decimal(15,2)) as commercial_ngr,\n        cast(nvl(c.eggr,0) - nvl(d.bonus_expected_costs,0) as decimal(15,2)) as commercial_engr,\n        cast(nvl(c.trading_ngr,0) as decimal(15,2)) as trading_ngr,\n        nvl(f.deposit_count,0) as deposit_count,\n        cast(nvl(f.deposit_amount,0) as decimal(15,2)) as deposit_amount,\n        nvl(g.withdrawal_count,0) as withdrawal_count,\n        cast(nvl(g.withdrawal_amount,0) as decimal(15,2)) as withdrawal_amount,\n        cast(sum(nvl(c.cash_bet_stake,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_cash_stakes,\n        cast(sum(nvl(c.total_stake,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_total_stakes,\n        cast(sum(nvl(c.total_payout,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_total_payout,\n        cast(sum(nvl(c.total_jackpot_contribution,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_total_jackpot_contribution,\n        cast(sum(nvl(d.bonus_costs,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_bonus_winnings,\n        cast(sum(nvl(c.cash_ggr,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_cash_ggr,\n        cast(sum(nvl(c.eggr,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_cash_eggr,\n        cast(sum(nvl(c.total_stake,0) - nvl(c.total_payout,0) - nvl(c.total_jackpot_contribution,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_total_ggr,\n        cast(sum(nvl(c.cash_ggr,0) - nvl(d.bonus_costs,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_commercial_ngr,\n        cast(sum(nvl(c.eggr,0) - nvl(d.bonus_expected_costs,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_commercial_engr,\n        cast(sum(nvl(c.trading_ngr,0)) over (partition by a.acco_id order by b.dt) as decimal(15,2)) as lifetime_trading_ngr,\n        cast(sum(nvl(c.cash_bet_stake,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_cash_stakes,\n        cast(sum(nvl(c.total_stake,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_total_stakes,\n        cast(sum(nvl(c.total_payout,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_total_payout,\n        cast(sum(nvl(c.total_jackpot_contribution,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_total_jackpot_contribution,\n        cast(sum(nvl(d.bonus_costs,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_bonus_winnings,\n        cast(sum(nvl(c.cash_ggr,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_cash_ggr,\n        cast(sum(nvl(c.eggr,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_cash_eggr,\n        cast(sum(nvl(c.total_stake,0) - nvl(c.total_payout,0) - nvl(c.total_jackpot_contribution,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_total_ggr,\n        cast(sum(nvl(c.cash_ggr,0) - nvl(d.bonus_costs,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_commercial_ngr,\n        cast(sum(nvl(c.eggr,0) - nvl(d.bonus_expected_costs,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_commercial_engr,\n        cast(sum(nvl(c.trading_ngr,0)) over (partition by a.acco_id order by b.dt rows between 364 preceding and current row) as decimal(15,2)) as l365d_trading_ngr,\n        cast(sum(nvl(c.cash_bet_stake,0)) over (partition by a.acco_id order by b.dt rows between 89 preceding and current row) as decimal(15,2)) as l90d_cash_stakes,\n        cast(sum(nvl(c.total_stake,0)) over (partition by a.acco_id order by b.dt rows between 89 preceding and c