(partition by a.acco_id order by b.dt rows between 27 preceding and current row) as decimal(15,2)) as l28d_total_payout,\n        cast(sum(nvl(c.total_jackpot_contribution,0)) over (partition by a.acco_id order by b.dt rows between 27 preceding and current row) as decimal(15,2)) as l28d_total_jackpot_contribution,\n        cast(sum(nvl(d.bonus_costs,0)) over (partition by a.acco_id order by b.dt rows between 27 preceding and current row) as decimal(15,2)) as l28d_bonus_winnings,\n        cast(sum(nvl(c.cash_ggr,0)) over (partition by a.acco_id order by b.dt rows between 27 preceding and current row) as decimal(15,2)) as l28d_cash_ggr,\n        cast(sum(nvl(c.eggr,0)) over (partition by a.acco_id order by b.dt rows between 27 preceding and current row) as decimal(15,2)) as l28d_cash_eggr,\n        cast(sum(nvl(c.total_stake,0) - nvl(c.total_payout,0) - nvl(c.total_jackpot_contribution,0)) over (partition by a.acco_id order by b.dt rows between 27 preceding and current row) as decimal(15,2)) as l28d_total_ggr,\n        cast(sum(nvl(c.cash_ggr,0) - nvl(d.bonus_costs,0)) over (partition by a.acco_id order by b.dt rows between 27 preceding and current row) as decimal(15,2)) as l28d_commercial_ngr,\n        cast(sum(nvl(c.eggr,0) - nvl(d.bonus_expected_costs,0)) over (partition by a.acco_id order by b.dt rows between 27 preceding and current row) as decimal(15,2)) as l28d_commercial_engr,\n        cast(sum(nvl(c.trading_ngr,0)) over (partition by a.acco_id order by b.dt rows between 27 preceding and current row) as decimal(15,2)) as l28d_trading_ngr,\n        cast(sum(nvl(c.cash_bet_stake,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_cash_stakes,\n        cast(sum(nvl(c.total_stake,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_total_stakes,\n        cast(sum(nvl(c.total_payout,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_total_payout,\n        cast(sum(nvl(c.total_jackpot_contribution,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_total_jackpot_contribution,\n        cast(sum(nvl(d.bonus_costs,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_bonus_winnings,\n        cast(sum(nvl(c.cash_ggr,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_cash_ggr,\n        cast(sum(nvl(c.eggr,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_cash_eggr,\n        cast(sum(nvl(c.total_stake,0) - nvl(c.total_payout,0) - nvl(c.total_jackpot_contribution,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_total_ggr,\n        cast(sum(nvl(c.cash_ggr,0) - nvl(d.bonus_costs,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_commercial_ngr,\n        cast(sum(nvl(c.eggr,0) - nvl(d.bonus_expected_costs,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_commercial_engr,\n        cast(sum(nvl(c.trading_ngr,0)) over (partition by a.acco_id order by b.dt rows between 6 preceding and current row) as decimal(15,2)) as l7d_trading_ngr\n    from casino_customers a\n    cross join (\n        select \n            calendar_date as dt \n        from fbg_analytics.product_and_customer.t_calendar \n        where calendar_date between \'2023-11-13\' and current_date-1\n                ) b\n    left join casino_activity c on a.acco_id = c.acco_id and b.dt = c.dt\n    left join commercial_bonus_costs d on a.acco_id = d.acco_id and b.dt = d.dt\n    left join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART e on a.acco_id = e.acco_id\n    left join deposits f on a.acco_id = f.acco_id and b.dt = f.deposit_date\n    left join withdrawals g on a.acco_id = g.acco_id and b.dt = g.withdrawal_date\n    where b.dt >= a.dt\n    and e.is_test_account = 0\n)\n\nselect * from revenue_join',NULL,'01c39a10-0212-644a-24dd-07031938b57f','Thread-6 (worker)','table','{"_message": "SUCCESS 341731511", "code": "SUCCESS", "rows_affected": 341731511, "query_id": "01c39a10-0212-644a-24dd-07031938b57f", "rows_inserted": 341731511, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('cb602e88-f585-4df8-ae75-6b33d339fbef.model.dbt_casino.reactivation_gaps','model.dbt_casino.reactivation_gaps','cb602e88-f585-4df8-ae75-6b33d339fbef','2026-04-09 21:42:42',
  current_timestamp::timestamp
,'reactivation_gaps','SUCCESS 754856','success','model',27.663613080978394,'2026-04-09T21:40:47.808519Z','2026-04-09T21:41:15.325482Z','2026-04-09T21:40:47.726798Z','2026-04-09T21:40:47.807959Z',754856,False,'with customer_activity as (\n    select distinct\n        acco_id,\n        settled_date_alk,\n        lag(settled_date_alk) over (partition by acco_id order by settled_date_alk) as prev_activity_date,\n        lead(settled_date_alk) over (partition by acco_id order by settled_date_alk) as next_activity_date\n    from FBG_ANALYTICS.CASINO.casino_revenue_history\n    where cash_stakes > 0\n),\n\ncasino_promo_ledger as (\n    select\n        acco_id,\n        bonus_campaign_id,\n        "Bonus Code",\n        "Description",\n        "SubCategory",\n        "Series",\n        promo_type,\n        min(date) as min_used_promo_datetime\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.CASINO_PROMOTIONS_LEDGER\n    where product = \'casino\'\n    and transaction = \'bonus used\'\n    and (\n        "SubCategory" in (\'Reactivation\', \'React\')\n        or "Description" like \'%REACT%\'\n        or "Bonus Code" like \'%REACT%\'\n    )\n    group by all\n),\n\ns2w_activity as (\n    select distinct\n        acco_id,\n        date(convert_timezone(\'UTC\', \'America/Anchorage\', time_awarded)) as spin_date,\n        1 as s2w_active_day\n    from FBG_SOURCE.OSB_SOURCE.F2P_GAME_SESSION_RESULTS\n),\n\n\nreactivations as (\n    select\n        acco_id,\n        settled_date_alk as reactivation_date,\n        prev_activity_date\n    from customer_activity\n    where prev_activity_date is not null\n    and datediff(day, prev_activity_date, settled_date_alk) > 28\n),\n\nchurns as (\n    select\n        acco_id,\n        settled_date_alk as last_active_date\n    from customer_activity\n    where\n        /* There is a next activity and the gap is > 28 days */\n        (next_activity_date is not null and datediff(day, settled_date_alk, next_activity_date) > 28)\n        or\n        /* There is no next activity, and it\'s been > 28 days since last activity as of today */\n        (next_activity_date is null and datediff(day, settled_date_alk, current_date) > 28)\n),\n\nreactivation_next_churn as (\n    select\n        a.acco_id,\n        a.reactivation_date,\n        a.prev_activity_date,\n        min(b.last_active_date) as next_churn_date\n    from reactivations a\n    left join churns b on a.acco_id = b.acco_id\n                       and b.last_active_date >= a.reactivation_date\n    group by all\n),\n\nactive_period_metrics as (\n    select\n        a.acco_id,\n        a.reactivation_date,\n        a.prev_activity_date as last_active_before_reactivation_date,\n        datediff(day, a.prev_activity_date, a.reactivation_date)-1 as days_inactive_before_reactivation,\n        a.next_churn_date,\n        count(distinct case when c.cash_stakes > 0 then c.settled_date_alk end) as active_days,\n        datediff(day, a.reactivation_date, a.next_churn_date)+1 as possible_active_days,\n        sum(c.commercial_ngr) as period_ngr,\n        sum(c.commercial_engr) as period_engr,\n        sum(c.deposit_amount) as period_deposit_amount,\n        sum(c.withdrawal_amount) as period_withdrawal_amount\n    from reactivation_next_churn a\n    left join FBG_ANALYTICS.CASINO.casino_revenue_history c on a.acco_id = c.acco_id and c.settled_date_alk between a.reactivation_date and a.next_churn_date\n    group by all\n),\n\ns2w_active_count as (\n    select\n        a.acco_id,\n        a.reactivation_date,\n        a.last_active_before_reactivation_date,\n        a.days_inactive_before_reactivation,\n        a.next_churn_date,\n        a.active_days,\n        sum(b.s2w_active_day) as s2w_active_days,\n        a.possible_active_days,\n        a.period_ngr,\n        a.period_engr,\n        a.period_deposit_amount,\n        a.period_withdrawal_amount\n    from active_period_metrics a\n    left join s2w_activity b on a.acco_id = b.acco_id and b.spin_date between a.reactivation_date and a.next_churn_date\n    group by all\n)\n\nselect \n    a.acco_id,\n    a.reactivation_date,\n    a.last_active_before_reactivation_date,\n    a.days_inactive_before_reactivation,\n    b.bonus_campaign_id as reactivation_bonus_campaign_id,\n    a.next_churn_date,\n    a.active_days,\n    a.s2w_active_days,\n    a.possible_active_days,\n    a.period_ngr,\n    a.period_engr,\n    a.period_deposit_amount,\n    a.period_withdrawal_amount\nfrom s2w_active_count a\nleft join casino_promo_ledger b on a.acco_id = b.acco_id and date(b.min_used_promo_datetime) = a.reactivation_date\nqualify row_number() over (partition by a.acco_id, a.reactivation_date order by b.min_used_promo_datetime) = 1',NULL,'01c39a14-0212-644a-24dd-07031939d4af','Thread-9 (worker)','table','{"_message": "SUCCESS 754856", "code": "SUCCESS", "rows_affected": 754856, "query_id": "01c39a14-0212-644a-24dd-07031939d4af", "rows_inserted": 754856, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('cb602e88-f585-4df8-ae75-6b33d339fbef.model.dbt_casino.reporting_f2p_metrics','model.dbt_casino.reporting_f2p_metrics','cb602e88-f585-4df8-ae75-6b33d339fbef','2026-04-09 21:42:42',
  current_timestamp::timestamp
,'reporting_f2p_metrics','SUCCESS 49307431','success','model',307.05371260643005,'2026-04-09T21:36:56.875468Z','2026-04-09T21:42:03.451886Z','2026-04-09T21:36:56.487428Z','2026-04-09T21:36:56.874562Z',49307431,False,'with all_spins as ( -- sum of spins for each account, day and segment (can be >1 spin per day)\n    select\n        a.acco_id,\n        date(convert_timezone(\'UTC\', \'America/New_York\', a.time_awarded)) as date_et,\n        replace(b.casino_segment, \'_Premium\', \'\') as f2p_segment,\n        b.description as f2p_prize_desc,\n        b.type as f2p_prize_type,\n        coalesce(b.bonus_round_level,0) as bonus_round_level,\n        case when lower(b.casino_segment) like \'%premium\' then \'Supercharged\' else \'Normal\' end as f2p_sc_ind,\n        count(distinct case when lower(b.casino_segment) like \'%premium\' then a.time_awarded end) as f2p_sc_spins,\n        count(distinct a.time_awarded) as f2p_spins\n    from FBG_SOURCE.OSB_SOURCE.F2P_GAME_SESSION_RESULTS a\n    inner join FBG_SOURCE.OSB_SOURCE.F2P_PRIZE_POOL b on a.prize_pool_id = b.id\n    inner join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART c on a.acco_id = c.acco_id\n    where c.is_test_account = 0\n    group by all\n),\n\nbonus_categories as ( -- promo ledger doesnt have all the info\n    select distinct\n        a.id as bonus_campaign_id,\n        try_parse_json(a.data):Bonus:bonusCode::varchar as bonus_code,\n        try_parse_json(a.data):Bonus:bonusOrigin::varchar as bonus_origin,\n        b.casino_segment as f2p_segment,\n        b.description as f2p_prize_desc,\n        b.type as f2p_prize_type,\n        coalesce(b.bonus_round_level,0) as bonus_round_level\n    from FBG_SOURCE.OSB_SOURCE.BONUS_CAMPAIGNS a\n    inner join FBG_SOURCE.OSB_SOURCE.F2P_PRIZE_POOL b on substr(regexp_replace(parse_json(a.data):Bonus:bonusCode::string,\'[^0-9]\',\'\'),8) = to_varchar(b.id)\n    where try_parse_json(a.data):Bonus:bonusOrigin::string = \'F2PGAME\'\n),\n\npromo_ledger as ( -- sum of awarded and costings for each account, day and segment (can be multiple per day)\n    select \n        a.acco_id,\n        date(convert_timezone(\'America/Anchorage\',\'America/New_York\',a.date)) as date_et,\n        replace(b.f2p_segment, \'_Premium\', \'\') as f2p_segment,\n        b.f2p_prize_desc,\n        b.f2p_prize_type,\n        coalesce(b.bonus_round_level,0) as bonus_round_level,\n        case when lower(b.f2p_segment) like \'%premium\' then \'Supercharged\' else \'Normal\' end as f2p_sc_ind,\n        count(distinct case when a.transaction = \'bonus awarded\' then a.date end) as f2p_awarded_tot_num,\n        sum(case when a.transaction = \'bonus awarded\' then a.amount else 0 end) as f2p_bonus_awarded_amt,\n        sum(case when a.transaction = \'bonus winnings\' then a.amount else 0 end) as f2p_bonus_cost_amt,\n        sum(case when a.transaction = \'bonus expected winnings\' then a.amount else 0 end) as f2p_bonus_exp_cost_amt\n    from FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.casino_promotions_ledger a\n    left join bonus_categories b on a.bonus_campaign_id = b.bonus_campaign_id\n    inner join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART c ON a.acco_id = c.acco_id \n    where lower(a."Series") = \'spin to win\'\n    and a.date is not null\n    and c.is_test_account = 0\n    group by all\n),\n\ncasino_activity as (\n    select\n        a.acco_id,\n        date(a.settled_time_est) as settled_date_est,\n        max(case when a.fund_type_id = 1 then 1 else 0 end) as casino_cash_bet_day,\n        case when min(a.fund_type_id) > 1 then 1 else 0 end as casino_bonus_only_bet_day,\n        1 as casino_bet_day\n    from FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_TRANSACTIONS_MART a\n    inner join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART b ON a.acco_id = b.acco_id \n    where b.is_test_account = 0\n    and date(a.settled_time_est) >= \'2024-08-06\'\n    and a.fund_type_id is not null\n    and a.stake > 0\n    and a.void = 0\n    group by all\n),\n\nunion_summary as (\n    select\n        acco_id,\n        date_et,\n        f2p_segment,\n        f2p_prize_desc,\n        f2p_prize_type,\n        bonus_round_level,\n        f2p_sc_ind,\n        sum(f2p_spins) as f2p_spins,\n        sum(f2p_sc_spins) as f2p_sc_spins,\n        sum(f2p_awarded_tot_num) as f2p_awarded_tot_num,\n        sum(f2p_bonus_awarded_amt) as f2p_bonus_awarded_amt,\n        sum(f2p_bonus_cost_amt) as f2p_bonus_cost_amt,\n        sum(f2p_bonus_exp_cost_amt) as f2p_bonus_exp_cost_amt\n    from (\n        select\n            acco_id, date_et, f2p_segment, f2p_prize_desc, f2p_prize_type, bonus_round_level, f2p_sc_ind,\n            f2p_spins, f2p_sc_spins, 0 as f2p_awarded_tot_num, 0 as f2p_bonus_awarded_amt, 0 as f2p_bonus_cost_amt, 0 as f2p_bonus_exp_cost_amt\n        from all_spins\n        \n        union all\n        \n        select\n            acco_id, date_et, f2p_segment, f2p_prize_desc, f2p_prize_type, bonus_round_level, f2p_sc_ind,\n            0 as f2p_spins, 0 as f2p_sc_spins, f2p_awarded_tot_num, f2p_bonus_awarded_amt, f2p_bonus_cost_amt, f2p_bonus_exp_cost_amt\n        from promo_ledger\n        ) \n    group by all\n),\n\ncasino_activity_and_f2p_merge as (\n    select\n        coalesce(a.acco_id, b.acco_id) as acco_id,\n        coalesce(a.date_et, b.settled_date_est) as date_et,\n        case when a.f2p_spins > 0 and b.acco_id is not null then \'OC Active & F2P Spin Same Day\'\n             when a.f2p_spins > 0 then \'F2P Spin Only\'\n             else \'Casino Only\'\n             end as activity_source,\n        a.f2p_segment,\n        a.f2p_prize_desc,\n        a.f2p_prize_type,\n        coalesce(a.bonus_round_level,0) as bonus_round_level,\n        a.f2p_sc_ind,\n        coalesce(a.f2p_spins, 0) as f2p_spins,\n        coalesce(a.f2p_sc_spins, 0) as f2p_sc_spins,\n        coalesce(a.f2p_awarded_tot_num, 0) as f2p_awarded_tot_num,\n        coalesce(a.f2p_bonus_awarded_amt, 0) as f2p_bonus_awarded_amt,\n        coalesce(a.f2p_bonus_cost_amt, 0) as f2p_bonus_cost_amt,\n        coalesce(a.f2p_bonus_exp_cost_amt, 0)  as f2p_bonus_exp_cost_amt,\n        coalesce(b.casino_cash_bet_day, 0) as casino_cash_bet_day,\n        coalesce(b.casino_bonus_only_bet_day, 0) as casino_bonus_only_bet_day,\n        coalesce(b.casino_bet_day, 0) as casino_bet_day\n    from union_summary a\n    full join casino_activity b on a.acco_id = b.acco_id and a.date_et = b.settled_date_est\n)\n\nselect \na.*,\nb.casino_cluster,\nc.casino_tier,\nc.casino_value,\ngreatest(coalesce(d.casino_vip,0), coalesce(d.vip,0)) as casino_vip,\ncoalesce(e.loyalty_tier, \'ONEmember\') f1_loyalty_tier,\ncoalesce(f.segment, \'None\') core_cluster,\ndate(g.casino_ftu_date_est) as casino_ftu_date_et,\ndate(g.first_deposit_date_est) as first_deposit_date_et,\nsysdate() as UpdateTimeUTC\nfrom casino_activity_and_f2p_merge a\nleft join FBG_ANALYTICS.CASINO.casino_behavioural_clusters_historical b on a.date_et between b.start_date and b.end_date and a.acco_id = b.acco_id\nleft join FBG_ANALYTICS.CASINO.casino_segments_historical c on a.date_et = c.date and a.acco_id = c.acco_id\nleft join FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.customer_account_history d on a.date_et between d.start_date and d.end_date and a.acco_id = d.acco_id\nleft join FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.F1_ATTRIBUTES_AUDITS e on a.date_et = e.as_of_date and a.acco_id = e.acco_id\nleft join FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.CASINO_SEGMENTATION f on a.date_et = f.last_updated_date and a.acco_id = f.acco_id\nleft join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART g ON a.acco_id = g.acco_id\nwhere a.date_et < date(sysdate()) + 1',NULL,'01c39a10-0212-6cb9-24dd-070319389a27','Thread-7 (worker)','table','{"_message": "SUCCESS 49307431", "code": "SUCCESS", "rows_affected": 49307431, "query_id": "01c39a10-0212-6cb9-24dd-070319389a27", "rows_inserted": 49307431, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}')
